def route(record: dict) -> str:
    required = {"case_id", "source", "stimulus", "environment", "response", "observed_ms", "target_ms", "owner"}
    absent = sorted(k for k in required if k not in record)
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = not (record["observed_ms"] >= record["target_ms"])
    return "PASS" if ok else "REJECT_QA_SCENARIO"

